/**
 * Senior Engineer Project Init Extension
 *
 * Commands:
 * - /init
 *
 * Creates AGENTS.md in the current project directory with:
 * - Senior engineering rules (append-only, do not edit)
 * - Project memory from /workflow teach (if available)
 */

import type { ExtensionAPI } from "@mariozechner/pi-coding-agent";
import * as fs from "node:fs/promises";
import * as path from "node:path";
import * as os from "node:os";

const MEMORY_ROOT = path.join(os.homedir(), ".pi", "agent", "memories", "senior-engineer-workflow", "projects");

function slugifyProjectPath(projectPath: string): string {
  return projectPath
    .replace(os.homedir(), "home")
    .replace(/[^a-zA-Z0-9]+/g, "-")
    .replace(/^-+|-+$/g, "")
    .toLowerCase();
}

async function readMemory(projectPath: string): Promise<string | null> {
  const memoryFile = path.join(MEMORY_ROOT, `${slugifyProjectPath(projectPath)}.md`);
  try {
    const content = await fs.readFile(memoryFile, "utf-8");
    return content;
  } catch {
    return null;
  }
}

