export default function (pi: ExtensionAPI) {
  pi.registerCommand("init", {
    description: "Create AGENTS.md with senior engineering rules and project memory",
    handler: async (_args, ctx) => {
      const projectPath = process.cwd();
      const projectName = path.basename(projectPath);
      const agentsPath = path.join(projectPath, "AGENTS.md");

      const existing = await fs.stat(agentsPath).then(() => true).catch(() => false);
      if (existing) {
        ctx.ui.notify("AGENTS.md sudah ada. Tidak dibuat ulang.", "warning");
        return;
      }

      const memory = await readMemory(projectPath);
      const content = agentsMdContent(projectName, memory);
      await fs.writeFile(agentsPath, content, "utf-8");

      ctx.ui.notify("AGENTS.md created", "info");
      pi.sendMessage({
        customType: "senior-engineer-init",
        display: true,
        content: [
          "# Project Init",
          "",
          `AGENTS.md created at: ${agentsPath}`,
          "",
          memory
            ? "Project memory from /workflow teach ditemukan dan sudah dimasukkan ke AGENTS.md."
            : "Tidak ada project memory. Jalankan /workflow teach dulu untuk menghasilkan project understanding, lalu jalankan /init lagi.",
          "",
          "**IMPORTANT:** AGENTS.md hanya boleh ditambahkan (append) — jangan diedit atau dihapus.",
        ].join("\n"),
      });
    },
  });
}
